/** 按亮度排序所有像素（从亮到暗），用于引导填充顺序 */
export function getSortedPixelsByBrightness(template: PaintingTemplate) {
  const pixels: { x: number; y: number; color: string; brightness: number }[] = []
  for (let y = 0; y < template.pixelData.length; y++) {
    for (let x = 0; x < template.pixelData[y].length; x++) {
      const color = template.pixelData[y][x]
      const r = parseInt(color.slice(1, 3), 16)
      const g = parseInt(color.slice(3, 5), 16)
      const b = parseInt(color.slice(5, 7), 16)
      const brightness = 0.299 * r + 0.587 * g + 0.114 * b
      pixels.push({ x, y, color, brightness })
    }
  }
  return pixels.sort((a, b) => b.brightness - a.brightness)
}

/** 获取名画列表（不含像素数据，用于前端下拉选择器） */
export function getPaintingsList() {
  return FAMOUS_PAINTINGS.map(({ id, title, artist, year }) => ({ id, title, artist, year }))
}
